def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def estimate_travel_time(start_position, end_position):
        """ Calculate travel time based on Euclidean distance and current truck speed. """
        distance = np.linalg.norm(start_position - end_position)
        return distance / truck_speed

    def calculate_wait_time(estimated_arrival, time_window):
        """ Calculate wait time based on the estimated arrival and customer's time window. """
        start, end = time_window
        if estimated_arrival < start:
            return start - estimated_arrival
        elif start <= estimated_arrival <= end:
            return 0
        else:
            return float('inf')  # high cost if outside the time window

    def order_customers_by_distance():
        """ Return customers ordered by closeness to the current truck position. """
        distances = [np.linalg.norm(cur_truck_pos - cust) for cust in unvisited_customers]
        return sorted(range(len(unvisited_customers)), key=lambda i: distances[i])

    def determine_if_better_option(truck_positions, customer_position):
        """ Check if there might be a closer truck for this task in future considerations. """
        own_distance = np.linalg.norm(cur_truck_pos - customer_position)
        other_distances = [np.linalg.norm(pos - customer_position) for pos in truck_positions if not np.array_equal(pos, cur_truck_pos)]
        return all(own_distance <= d for d in other_distances)

    # Order customers by proximity and the feasibility of other trucks taking the task.
    customer_indices = order_customers_by_distance()
    feasible_customers = [idx for idx in customer_indices if determine_if_better_option(all_truck_pos, unvisited_customers[idx])]

    # Select the best customer based on combined priority of distance, wait time, and truck efficiency.
    best_time = float('inf')
    best_node = None
    for idx in feasible_customers:
        travel_time = estimate_travel_time(cur_truck_pos, unvisited_customers[idx])
        arrival_time = current_time + travel_time
        wait_time = calculate_wait_time(arrival_time, time_windows[idx])
        total_time = travel_time + wait_time

        if total_time < best_time:
            best_time = total_time
            best_node = idx

    if best_node is None:
        best_node = feasible_customers[0] if feasible_customers else 0  # Default fallback to the closest if no feasible option found.

    return best_node

